import{_ as o,c as r,m as t,a as e,t as s,o as n}from"./chunks/framework.9QHaLlVJ.js";const V=JSON.parse('{"title":"APP 测试 - Postern 绕过客户端检测抓包","description":"","frontmatter":{"title":"APP 测试 - Postern 绕过客户端检测抓包"},"headers":[],"relativePath":"doc/平台/Windows/游戏App抓包.md","filePath":"packages/doc/src/平台/Windows/游戏App抓包.md","lastUpdated":1705591713000}'),i={name:"doc/平台/Windows/游戏App抓包.md"},d={id:"frontmatter-title",tabindex:"-1"},l=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),P=t("ul",null,[t("li",null,[t("a",{href:"https://www.malavida.com/en/soft/postern/android/",target:"_blank",rel:"noreferrer"},"Postern 下载")])],-1),c=t("p",null,"目前市场上大多数的 APP 都针对客户端做代理检测，最典型的场景就是无法通过 WiFi 代理抓取 APP 数据包，但很少会对 APP 经过 VPN 的流量做检测，因此可以通过在 Android 等设备上启动一个 VPN 服务，让 APP 的所有流量都先经过 VPN 服务，再抓取 APP 的网络数据包。在前面的文章介绍了使用 HttpCanary 进行 VPN 代理抓包，但只能在 HttpCanary 软件上做操作，分析抓包等操作比较繁琐，而通过 Postern 工具可以将经过 VPN 的 APP 流量进一步转发给 BurpSuite 等抓包分析工具更方便做 APP 测试。",-1),p=t("h2",{id:"postern",tabindex:"-1"},[e("Postern "),t("a",{class:"header-anchor",href:"#postern","aria-label":'Permalink to "Postern"'},"​")],-1),_=t("p",null,"是一个基于 V** 的 Android 全局代理工具，并且可将 V** 流量进行二次转发。支持的代理协议有：SSH，Shadowsocks，SOCKS5，HTTPS/HTTP CONNECT，gfw.press。",-1);function h(a,f,m,A,u,N){return n(),r("div",null,[t("h1",d,[e(s(a.$frontmatter.title)+" ",1),l]),P,c,p,_])}const w=o(i,[["render",h]]);export{V as __pageData,w as default};
